scripts.build:
rm -rf dist && bun build src/cli/index.tsx --outdir dist/cli --target bun --external ink --external react --external chalk --external @modelcontextprotocol/sdk && bun build src/mcp/index.ts --outdir dist/mcp --target bun --external @modelcontextprotocol/sdk && printf '#!/usr/bin/env bun
import "./index.js";
' > dist/mcp/bin.js && chmod +x dist/mcp/bin.js && bun build src/server/index.ts --outdir dist/server --target bun && printf '#!/usr/bin/env bun
import "./index.js";
' > dist/server/bin.js && chmod +x dist/server/bin.js && bun build src/sdk/index.ts --outdir dist/sdk --target bun && bun build src/index.ts --outdir dist --target bun && tsc --emitDeclarationOnly --outDir dist

